mapper.select:
WITH base AS ( SELECT LEAST(TRIM(t1.target), TRIM(t2.target)) AS target_a, GREATEST(TRIM(t1.target), TRIM(t2.target)) AS target_b, c.global_highest_phase_score AS score, c.global_highest_phase AS phase_name, c.drug_id FROM ci_tracking_latest c CROSS JOIN LATERAL unnest(c.targets) AS t1(target) CROSS JOIN LATERAL unnest(c.targets) AS t2(target) WHERE c.disease_id IN
#{id}
AND c.global_highest_phase IN
#{p}
AND TRIM(t1.target) < TRIM(t2.target) ), agg AS ( SELECT target_a, target_b, MAX(score) AS max_score, COUNT(DISTINCT drug_id) AS drug_count FROM base GROUP BY target_a, target_b ), result AS ( SELECT DISTINCT ON (a.target_a, a.target_b) a.target_a, a.target_b, a.max_score AS score, a.drug_count, b.phase_name FROM agg a JOIN base b ON b.target_a = a.target_a AND b.target_b = a.target_b AND b.score = a.max_score ORDER BY a.target_a, a.target_b ) SELECT * FROM result ORDER BY target_a, target_b

SELECT TRIM(t.target) AS target, MAX(c.global_highest_phase_score) AS max_score FROM ci_tracking_latest c CROSS JOIN LATERAL unnest(c.targets) AS t(target) WHERE c.disease_id IN
#{id}
AND c.global_highest_phase IN
#{p}
GROUP BY TRIM(t.target) ORDER BY MAX(c.global_highest_phase_score) DESC, TRIM(t.target)

SELECT DISTINCT c.drug_name_en AS drug_name_en, c.originator AS originator, c.research_institute AS research_institute, c.global_highest_phase AS highest_phase, c.global_highest_phase_score AS highest_phase_score, TO_CHAR(c.indication_top_global_start_date, 'YYYY-MM-DD') AS highest_phase_date, c.nct_id AS nct_id FROM ci_tracking_latest c WHERE c.disease_id IN
#{id}
AND c.targets @> ARRAY[#{target}, #{pairTarget}]::text[] AND c.global_highest_phase IN
#{p}
ORDER BY highest_phase_score DESC LIMIT 20
